// Phase-A corpus: representative tool outputs used to baseline and benchmark the
// compressor WITHOUT spending model quota. Each fixture declares the signals that
// MUST survive any admission decision — the eval fails if a compressor drops them.
//
// Big fixtures are generated by repetition (not committed as large blobs) so the
// corpus stays cheap to ship while still exercising the head/tail truncation path.

export type FixtureKind = "success" | "failure" | "dense" | "secret" | "huge";

export interface Fixture {
  name: string;
  kind: FixtureKind;
  /** Command-family hint, mirrors what a host adapter would pass. */
  cmd?: string;
  raw: string;
  /** Substrings that MUST appear in the compressed output (admission must keep). */
  requiredSignals: string[];
  /** Secret literals seeded for the phase-B redaction test (unused in phase A). */
  secrets?: string[];
}

const repeat = (line: string, n: number): string =>
  Array.from({ length: n }, (_, i) => line.replace("{i}", String(i + 1))).join("\n");

// A clean passing run: lots of near-identical lines + the only signal is the tail summary.
const SUCCESS = [
  "$ npm test",
  "> zemory@0.0.1 test",
  "",
  repeat("  ✓ case {i} passed (2 ms)", 180),
  "",
  "Test Suites: 12 passed, 12 total",
  "Tests:       180 passed, 180 total",
  "Time:        3.142 s",
].join("\n");

// A failing run: the error block + final summary must survive even after truncation.
const FAILURE = [
  "$ npm test",
  repeat("  ✓ case {i} passed (1 ms)", 40),
  "",
  "  ● AuthError: invalid token signature",
  "      at verify (src/auth.ts:42:11)",
  "      at handler (src/server.ts:88:7)",
  "",
  "Tests:       1 failed, 219 passed, 220 total",
].join("\n");

// Dense code: short, no noise → must come back near-verbatim (no over-compression).
const DENSE = [
  "export function rrf(ranks: number[][], k = 60): number[] {",
  "  const score = new Map<number, number>();",
  "  for (const list of ranks)",
  "    list.forEach((id, i) => score.set(id, (score.get(id) ?? 0) + 1 / (k + i + 1)));",
  "  return [...score.entries()].sort((a, b) => b[1] - a[1]).map(([id]) => id);",
  "}",
].join("\n");

// Output carrying secrets (for phase-B redaction); also a valid corpus member now.
const SECRET = [
  "$ deploy --print-env",
  "ANTHROPIC_API_KEY=sk-ant-api03-DEADBEEFdeadbeefDEADBEEFdeadbeef0123456789abcdefAA",
  "AWS_ACCESS_KEY_ID=AKIAIOSFODNN7EXAMPLE",
  "deploy ok → https://example.test/app",
].join("\n");

// Huge build log: thousands of progress lines, one error in the middle, summary at the end.
const HUGE = [
  "$ webpack build",
  repeat("[{i}/5000] compiling module chunk-{i}.js", 2500),
  "ERROR in ./src/missing.ts",
  "  Module not found: Cannot resolve './does-not-exist'",
  repeat("[{i}/5000] compiling module chunk-{i}.js", 2500),
  "",
  "webpack compiled with 1 error",
  "Build failed in 18.4s",
].join("\n");

export const FIXTURES: Fixture[] = [
  { name: "test-success", kind: "success", cmd: "test", raw: SUCCESS, requiredSignals: ["180 passed", "12 passed"] },
  {
    name: "test-failure",
    kind: "failure",
    cmd: "test",
    raw: FAILURE,
    requiredSignals: ["AuthError: invalid token signature", "src/auth.ts:42:11", "1 failed"],
  },
  { name: "dense-code", kind: "dense", raw: DENSE, requiredSignals: ["export function rrf", "1 / (k + i + 1)"] },
  {
    name: "secret-env",
    kind: "secret",
    raw: SECRET,
    requiredSignals: ["deploy ok"],
    secrets: ["sk-ant-api03-DEADBEEFdeadbeefDEADBEEFdeadbeef0123456789abcdefAA", "AKIAIOSFODNN7EXAMPLE"],
  },
  {
    name: "huge-build-log",
    kind: "huge",
    cmd: "build",
    raw: HUGE,
    requiredSignals: ["Module not found: Cannot resolve './does-not-exist'", "Build failed in 18.4s"],
  },
];
